import{_ as e,c as a,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Política de Privacidade: Proteção de Dados | OpenCodeDocs","description":"Entenda a política de privacidade e medidas de proteção de dados do OpenCodeDocs. Como coletamos, usamos e armazenamos suas informações pessoais e seus direitos.","frontmatter":{"title":"Política de Privacidade: Proteção de Dados | OpenCodeDocs","sidebarTitle":"Para onde vão seus dados","subtitle":"Política de Privacidade: Proteção de Dados","description":"Entenda a política de privacidade e medidas de proteção de dados do OpenCodeDocs. Como coletamos, usamos e armazenamos suas informações pessoais e seus direitos."},"headers":[],"relativePath":"pt/privacy.md","filePath":"pt/privacy.md"}'),r={name:"pt/privacy.md"};function t(d,o,n,c,l,m){return s(),a("div",null,[...o[0]||(o[0]=[i('<h1 id="politica-de-privacidade" tabindex="-1">Política de Privacidade <a class="header-anchor" href="#politica-de-privacidade" aria-label="Permalink to &quot;Política de Privacidade&quot;">​</a></h1><p>Última atualização: 2026-01-01</p><p>Obrigado por usar o OpenCodeDocs. Levamos muito a sério sua privacidade e a proteção de suas informações pessoais. Esta política de privacidade ajudará você a entender como coletamos, usamos, armazenamos e protegemos suas informações pessoais.</p><h2 id="_1-informacoes-que-coletamos" tabindex="-1">1. Informações que coletamos <a class="header-anchor" href="#_1-informacoes-que-coletamos" aria-label="Permalink to &quot;1. Informações que coletamos&quot;">​</a></h2><p>Ao usar os serviços do OpenCodeDocs, podemos coletar os seguintes tipos de informações:</p><h3 id="informacoes-da-conta" tabindex="-1">Informações da conta <a class="header-anchor" href="#informacoes-da-conta" aria-label="Permalink to &quot;Informações da conta&quot;">​</a></h3><ul><li><strong>Endereço de e-mail</strong>: usado para registro de conta, verificação de login e notificações importantes</li><li><strong>Nome de usuário</strong>: o nome de exibição que você escolheu</li><li><strong>Informações da conta do GitHub</strong>: se você optar por usar login do GitHub, obteremos suas informações públicas</li></ul><h3 id="dados-de-uso" tabindex="-1">Dados de uso <a class="header-anchor" href="#dados-de-uso" aria-label="Permalink to &quot;Dados de uso&quot;">​</a></h3><ul><li><strong>Histórico de navegação</strong>: páginas de tutorial que você acessou e horários de acesso</li><li><strong>Comportamento de interação</strong>: operações como cópia de código, navegação entre seções, etc.</li><li><strong>Histórico de pesquisa</strong>: palavras-chave que você pesquisou no site</li></ul><h3 id="informacoes-do-dispositivo" tabindex="-1">Informações do dispositivo <a class="header-anchor" href="#informacoes-do-dispositivo" aria-label="Permalink to &quot;Informações do dispositivo&quot;">​</a></h3><ul><li><strong>Tipo de navegador</strong>: Chrome, Firefox, Safari, etc.</li><li><strong>Sistema operacional</strong>: Windows, macOS, Linux, etc.</li><li><strong>Endereço IP</strong>: usado para proteção de segurança e otimização regional</li></ul><h2 id="_2-como-usamos-as-informacoes" tabindex="-1">2. Como usamos as informações <a class="header-anchor" href="#_2-como-usamos-as-informacoes" aria-label="Permalink to &quot;2. Como usamos as informações&quot;">​</a></h2><p>As informações coletadas serão usadas para os seguintes propósitos:</p><ul><li><strong>Fornecer serviços</strong>: garantir que você possa acessar e usar o conteúdo do tutorial normalmente</li><li><strong>Experiência personalizada</strong>: lembrar seu progresso de leitura e preferências</li><li><strong>Melhoria do produto</strong>: analisar padrões de uso para otimizar conteúdo e funcionalidades</li><li><strong>Segurança</strong>: detectar comportamentos anormais e prevenir abusos</li><li><strong>Envio de notificações</strong>: enviar lembretes de atualizações de tutoriais e anúncios importantes (é possível cancelar a inscrição)</li></ul><h2 id="_3-compartilhamento-e-divulgacao-de-informacoes" tabindex="-1">3. Compartilhamento e divulgação de informações <a class="header-anchor" href="#_3-compartilhamento-e-divulgacao-de-informacoes" aria-label="Permalink to &quot;3. Compartilhamento e divulgação de informações&quot;">​</a></h2><p>Não vendemos suas informações pessoais. Podemos compartilhar apenas nos seguintes casos:</p><ul><li><strong>Provedores de serviços terceirizados</strong>: como Vercel (hospedagem), Plausible (análises), eles só podem acessar as informações necessárias para cumprir suas responsabilidades</li><li><strong>Requisitos legais</strong>: divulgação de acordo com leis e regulamentos ou requisitos governamentais</li><li><strong>Proteção de direitos</strong>: situações necessárias para proteger os direitos e interesses do OpenCodeDocs e dos usuários</li></ul><h2 id="_4-armazenamento-e-seguranca-de-dados" tabindex="-1">4. Armazenamento e segurança de dados <a class="header-anchor" href="#_4-armazenamento-e-seguranca-de-dados" aria-label="Permalink to &quot;4. Armazenamento e segurança de dados&quot;">​</a></h2><ul><li><strong>Local de armazenamento</strong>: os dados são armazenados em servidores seguros localizados nos EUA e na região Ásia-Pacífico</li><li><strong>Medidas de criptografia</strong>: dados em trânsito usam criptografia TLS/SSL, dados sensíveis são armazenados com criptografia AES-256</li><li><strong>Controle de acesso</strong>: acesso restrito de pessoal interno aos dados</li><li><strong>Período de retenção</strong>: após o cancelamento da conta, os dados pessoais serão excluídos em até 30 dias</li></ul><h2 id="_5-seus-direitos" tabindex="-1">5. Seus direitos <a class="header-anchor" href="#_5-seus-direitos" aria-label="Permalink to &quot;5. Seus direitos&quot;">​</a></h2><p>De acordo com a Lei de Proteção de Dados Pessoais e GDPR, você tem os seguintes direitos:</p><ul><li><strong>Direito de acesso</strong>: você tem o direito de visualizar suas informações pessoais que mantemos sobre você</li><li><strong>Direito de correção</strong>: você tem o direito de solicitar a correção de informações pessoais imprecisas</li><li><strong>Direito de exclusão</strong>: você tem o direito de solicitar a exclusão de suas informações pessoais</li><li><strong>Direito de exportação</strong>: você tem o direito de exportar seus dados em um formato comum</li><li><strong>Direito de retirar consentimento</strong>: você tem o direito de retirar o consentimento que você deu a qualquer momento</li></ul><p>Para exercer os direitos acima, entre em contato conosco através das informações de contato abaixo.</p><h2 id="_6-politica-de-cookies" tabindex="-1">6. Política de Cookies <a class="header-anchor" href="#_6-politica-de-cookies" aria-label="Permalink to &quot;6. Política de Cookies&quot;">​</a></h2><p>Usamos os seguintes tipos de Cookie:</p><ul><li><strong>Cookie essencial</strong>: manter o estado de login, lembrar preferências de idioma</li><li><strong>Cookie de análise</strong>: estatísticas de tráfego e padrões de uso (usando Plausible, que é amigável à privacidade)</li><li><strong>Cookie de publicidade</strong>: <ul><li>Fornecedores terceirizados (incluindo o Google) usam cookies para exibir anúncios com base no histórico de visitas do usuário ao seu site e outros sites.</li><li>O Google usa cookies de publicidade para permitir que ele e seus parceiros exibam anúncios aos usuários com base no histórico de visitas dos usuários ao seu site e/ou outros sites na internet.</li><li>Os usuários podem visitar <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Configurações de anúncios do Google</a> para desativar anúncios personalizados. Alternativamente, você pode direcionar os usuários para visitar <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a> para desativar cookies usados por fornecedores terceirizados para anúncios personalizados.</li></ul></li></ul><p>Você pode gerenciar cookies através das configurações do seu navegador. Desativar cookies essenciais pode afetar o funcionamento normal de algumas funcionalidades.</p><h2 id="_7-entre-em-contato-conosco" tabindex="-1">7. Entre em contato conosco <a class="header-anchor" href="#_7-entre-em-contato-conosco" aria-label="Permalink to &quot;7. Entre em contato conosco&quot;">​</a></h2><p>Se você tiver alguma dúvida sobre esta política de privacidade ou precisar exercer seus direitos de dados, entre em contato com:</p><ul><li><strong>E-mail</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Tempo de resposta</strong>: responderemos à sua solicitação em até 15 dias úteis</li></ul>',30)])])}const g=e(r,[["render",t]]);export{p as __pageData,g as default};
